protected PurchReceiptsListHeaderTmp initializePurchaseReceiptsListHeader(VendReceiptsListJour _vendReceiptsListJour)
{
    PurchReceiptsListHeaderTmp purchReceiptsListHeaderTmpCreated = next initializePurchaseReceiptsListHeader(_vendReceiptsListJour);

    FWFTextBlockReportTextInit::newParameters(purchReceiptsListHeaderTmpCreated, _vendReceiptsListJour).addTexts();

    return purchReceiptsListHeaderTmpCreated;
}

protected PurchReceiptsListDetailsTmp initializePurchaseReceiptsListLine(PurchReceiptsListHeaderTmp _purchReceiptsListHeaderTmp, VendReceiptsListJour _vendReceiptsListJour, VendReceiptsListTrans _vendReceiptsListTrans, InventDim _vendReceiptsListTransInventDim)
{
    PurchReceiptsListDetailsTmp purchReceiptsListDetailsTmpCreated = next initializePurchaseReceiptsListLine(_purchReceiptsListHeaderTmp, _vendReceiptsListJour, _vendReceiptsListTrans, _vendReceiptsListTransInventDim);

    FWFTextBlockReportTextInit::newParameters(purchReceiptsListDetailsTmpCreated, _vendReceiptsListTrans).addTexts();

    return purchReceiptsListDetailsTmpCreated;
}
